import { createFileRoute } from "@tanstack/react-router";
import { useGetPublicActionPageQueryOptions } from "@workspace/api-client/public";
import type { PublicV3ActionPageResponse } from "@workspace/api-client/types";

export const Route = createFileRoute("/lead/$slug/$token")({
  component: RouteComponent,
  errorComponent: LeadErrorComponent,
  loader: async ({
    context: { queryClient },
    params: { slug, token },
  }): Promise<{ actionPage: PublicV3ActionPageResponse }> => {
    const options = useGetPublicActionPageQueryOptions({
      actionPageSlug: token,
      accountSlug: slug,
    });
    const actionPage = await queryClient.ensureQueryData(options);

    return { actionPage };
  },
});

function RouteComponent() {
  const { actionPage } = Route.useLoaderData();

  return (
    <div className="flex rounded-lg shadow-md bg-background-light">
      <h1>{actionPage.headerTitleText}</h1>
      {actionPage.description && <p>{actionPage.description}</p>}
      <div className="">Welcom back {actionPage.account}</div>
    </div>
  );
}

function LeadErrorComponent({ error }: { error: Error }) {
  return <div>Error: {error.message}</div>;
}

